  ('elementary-8b44517b-moex-00837', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '主管機關或檢查機構於接獲勞工對事業單位違反勞工法令規定之申訴後，應為必要之調查，並於幾日內 將處理情形，以書面通知勞工？', '["90日", "60日", "45日", "30日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00838', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列關於雇主違反勞工退休金條例第14條第1項之規定，未按時提繳或繳足退休金之敘述，何者正確？', '["按自僱用之日起至繳足退休金之前一日止之提繳標準，處四倍罰鍰", "按自未提繳或繳足之日起至繳足退休金之前一日止之提繳標準，處二倍罰鍰", "自期限屆滿之次日起至完繳前一日止，每逾一日加徵其應提繳金額百分之三滯納金至應提繳金額之一 倍為止", "勞工受有損害者，由勞動部勞工保險局與雇主連帶負損害賠償責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00839', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '雇主應為依勞工退休金條例第7條第1項規定之勞工，負擔提繳之退休金比率為何？', '["不得高於勞工每月工資百分之六", "不得低於勞工自願提繳退休金之比率", "不得低於勞工每月工資百分之六", "依勞工自願提繳退休金之比率定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
