  ('elementary-8b44517b-moex-00841', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列關於積欠工資墊償基金之敘述，何者正確？', '["勞工依勞動基準法第28條第1項所列債權受償順序與第一順位抵押權、質權或留置權所擔保之債權相同", "雇主一旦積欠勞工工資，勞工即得向積欠工資墊償基金請求墊償之", "勞工本於勞動契約所積欠之工資全額，有最優先受清償之權", "積欠工資墊償基金依規定墊償後，法院應定期限命雇主將墊款償還積欠工資墊償基金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00842', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', 'A公司與員工間因加班費遲遲未發致生勞資爭議，該爭議屬於：', '["調整事項之勞資爭議", "調解事項之勞資爭議", "權利事項之勞資爭議", "勞資會議之勞資爭議"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
